import json

alert = inputs.get('alert', inputs.get('alert_data', {}))
if isinstance(alert, str):
    try:
        alert = json.loads(alert)
    except Exception:
        alert = {'raw': alert}
if not isinstance(alert, dict):
    alert = {'raw': str(alert)}

summary = {
    'title': alert.get('name') or alert.get('alert_type') or 'unknown alert',
    'severity': alert.get('severity') or alert.get('level') or 'unknown',
    'src_ip': alert.get('src_ip') or alert.get('attacker') or '',
    'dst_ip': alert.get('dst_ip') or alert.get('victim') or '',
    'recommendation': '请结合资产重要性、请求响应和同源告警继续核查。'
}
outputs['summary'] = summary
outputs['text'] = f"{summary['title']} [{summary['severity']}] {summary['src_ip']} -> {summary['dst_ip']}"
